#### createFal() Factory Function:
```typescript
export function createFal(options: FalProviderSettings = {}): FalProvider {
  // 1. Load and validate API key
  const getHeaders = () => ({
    Authorization: `Key ${apiKey}`,
    ...options.headers,
  });

  // 2. Create model factories for each capability
  const createImageModel = (modelId: FalImageModelId) =>
    new FalImageModel(modelId, {
      provider: 'fal.image',
      baseURL: baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  // 3. Return provider object with methods
  return {
    specificationVersion: 'v3' as const,
    imageModel: createImageModel,
    image: createImageModel,
    languageModel: () => throw NoSuchModelError(...),
    // ... other model factories
  };
}

export const fal = createFal(); // Singleton with env-based config
```

**Key Patterns:**
- Factory function returns object with `specificationVersion: 'v3'`
- Each capability has both singular (`image`) and `ModelVariant` (`imageModel`) methods
- Models that don't apply throw `NoSuchModelError`
- All models get provider name prefixed: `'fal.image'`, `'fal.video'`, etc.

