      safetyTolerance: z.enum(['1','2','3','4','5','6']).or(z.number()).nullish(),
      useMultipleImages: z.boolean().nullish(),

      // snake_case (deprecated, supported for backwards compat)
      image_url: z.string().nullish(),
      mask_url: z.string().nullish(),
      // ... all snake_case variants
    })
    .passthrough()  // Allow unknown keys for forward compatibility
    .transform(data => {
      // Maps snake_case to camelCase, tracks deprecation
      // Passes through unknown keys
    }),
  ),
);

export type FalImageModelOptions = InferSchema<
  typeof falImageModelOptionsSchema
>;
