### 10. OPENAI IMAGE MODEL (openai-image-model.ts)

```typescript
export class OpenAIImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  get maxImagesPerCall(): number {
    return modelMaxImagesPerCall[this.modelId] ?? 1;
  }

  async doGenerate(options: Parameters<ImageModelV3['doGenerate']>[0]):
    Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    // Warnings for unsupported features
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details: 'This model does not support aspect ratio. Use `size` instead.',
      });
    }

    if (seed != null) {
      warnings.push({ type: 'unsupported', feature: 'seed' });
    }

    // Image editing uses multipart form data
    if (files != null) {
      const { value: response, responseHeaders } = await postFormDataToApi({
        url: this.config.url({ path: '/images/edits', modelId: this.modelId }),
        formData: convertToFormData<OpenAIImageEditInput>({
          model: this.modelId,
          prompt,
          image: files,
          mask,
          // ... other params
        }),
      });
      return { images: response.data.map(item => item.b64_json), ... };
    }

    // Standard image generation
    const { value: response, responseHeaders } = await postJsonToApi({
      url: this.config.url({ path: '/images/generations', modelId: this.modelId }),
      body: {
        model: this.modelId,
        prompt,
        n,
        size,
        response_format: 'b64_json',
        // ... other params
      },
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      usage: { inputTokens, outputTokens, totalTokens },
      response: { timestamp, modelId, headers },
      providerMetadata: {
        openai: {
          images: response.data.map((item, index) => ({
            revisedPrompt: item.revised_prompt,
            created: response.created,
            size: response.size,
            quality: response.quality,
          })),
        },
      },
    };
  }
}
```

**Key Differences from FAL:**
- Uses form data for image editing (multipart), JSON for generation
- Warns about unsupported features (aspectRatio, seed)
- Returns base64-encoded images (`b64_json`)
- Model-specific `maxImagesPerCall` mapping
- Different metadata structure per model

