### Step 5 — `src/pixelart-image-options.ts`

Defines the Zod schema for provider-specific options passed via `providerOptions.pixelart`.
Uses `lazySchema` (same as `packages/fal/src/fal-image-options.ts`) to avoid circular-dep issues.

```typescript
import { InferSchema, lazySchema, zodSchema } from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

export const pixelArtImageOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      style: z.enum(['pixel', 'retro', '8bit']).nullish(),
      pixelDensity: z.number().min(1).max(16).nullish(),
    }).passthrough(),
  ),
);

export type PixelArtImageModelOptions = InferSchema<typeof pixelArtImageOptionsSchema>;
```

**Rationale for `.passthrough()`**: keeps the schema forward-compatible for future options without breaking older SDK versions.

---

### Step 6 — `src/pixelart-image-model.ts`

Implements `ImageModelV3`. Key design decisions mirroring `packages/fal/src/fal-image-model.ts`:

- **Unsupported features** → emit `SharedV3Warning` and skip: `aspectRatio`, `seed`, `files` (image editing), `mask` (inpainting).
- **Provider options** parsed with `parseProviderOptions` using the schema above.
- **API call** via `postJsonToApi` to `${baseURL}/images/generate`.
- **Response format**: expects `{ created, data: [{ b64_json, style, pixel_density }] }`.
- **Returns base64 strings** (not Uint8Array), following the OpenAI DALL-E pattern.

```typescript
import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders, createJsonErrorResponseHandler, createJsonResponseHandler,
  FetchFunction, parseProviderOptions, postJsonToApi, resolve,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import type { PixelArtImageModelId } from './pixelart-image-settings';
import { pixelArtImageOptionsSchema } from './pixelart-image-options';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: { currentDate?: () => Date };
}

// Response schema
const pixelArtResponseSchema = z.object({
  created: z.number(),
  data: z.array(z.object({
    b64_json: z.string(),
    style: z.string().nullish(),
    pixel_density: z.number().nullish(),
  })),
});

// Error schema
const pixelArtErrorSchema = z.object({
  error: z.object({ message: z.string(), type: z.string().nullish(), code: z.string().nullish() }),
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: error => error.error.message,
});

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string { return this.config.provider; }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(options: Parameters<ImageModelV3['doGenerate']>[0])
    : Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {

    const { prompt, n, size, aspectRatio, seed, providerOptions,
            files, mask, abortSignal, headers } = options;
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) warnings.push({
      type: 'unsupported', feature: 'aspectRatio',
      details: 'PixelArt does not support aspectRatio. Use `size` instead.',
    });
    if (seed != null) warnings.push({ type: 'unsupported', feature: 'seed' });
    if (files != null && files.length > 0) warnings.push({
      type: 'unsupported', feature: 'image editing',
      details: 'PixelArt does not support image editing (files parameter).',
    });
    if (mask != null) warnings.push({
      type: 'unsupported', feature: 'mask',
      details: 'PixelArt does not support inpainting.',
    });

    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageOptionsSchema,
    });

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(await resolve(this.config.headers), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        size: size ?? '512x512',
        ...(pixelArtOptions?.style != null && { style: pixelArtOptions.style }),
        ...(pixelArtOptions?.pixelDensity != null && { pixel_density: pixelArtOptions.pixelDensity }),
        response_format: 'b64_json',
      },
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(pixelArtResponseSchema),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          images: response.data.map(item => ({
            style: item.style ?? null,
            pixelDensity: item.pixel_density ?? null,
          })),
          created: response.created,
        },
      },
    };
  }
}
```

