        num_images: 1,
        prompt: 'Edit this image',
      });
      expect(requestBody.image_url).toBeUndefined();
    });

    it('should allow imageUrl via provider options', async () => {
      await createBasicModel().doGenerate({
        prompt: 'Edit via provider options',
