import { type InferSchema, lazySchema, zodSchema } from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

/**
 * Provider-specific options for the PixelArt image model.
 * Pass these via `providerOptions: { pixelart: { ... } }`.
 */
export const pixelArtImageOptionsSchema = lazySchema(() =>
  zodSchema(
    z
      .object({
        /**
         * The artistic style to apply to the generated image.
         * - `'pixel'`: Classic pixel art style
         * - `'retro'`: Retro-inspired aesthetic with limited color palette
         * - `'8bit'`: 8-bit video game style
         */
        style: z.enum(['pixel', 'retro', '8bit']).nullish(),

        /**
         * Controls the density of pixels in the output image.
         * Higher values produce more detailed pixel art.
         * Range: 1–16. Defaults to 4 if not specified.
         */
        pixelDensity: z.number().min(1).max(16).nullish(),
      })
      .passthrough(),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageOptionsSchema
>;

