import type { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const prompt = 'A cute dragon in a pixel art forest';

const BASE_URL = 'https://api.example.com/v1';
const GENERATE_URL = `${BASE_URL}/images/generate`;

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixelart-standard-v1', {
    provider: 'pixelart.image',
    baseURL: BASE_URL,
    headers: headers ?? { Authorization: 'Bearer test-key' },
    fetch,
    _internal: { currentDate },
  });
}

const DEFAULT_RESPONSE = {
  created: 1700000000,
  data: [{ b64_json: 'aGVsbG8=' }],
};

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    [GENERATE_URL]: {
      response: {
        type: 'json-value',
        body: DEFAULT_RESPONSE,
      },
    },
  });

  describe('constructor', () => {
    it('should expose correct provider and model information', () => {
      const model = createBasicModel();

      expect(model.provider).toBe('pixelart.image');
      expect(model.modelId).toBe('pixelart-standard-v1');
      expect(model.specificationVersion).toBe('v3');
      expect(model.maxImagesPerCall).toBe(4);
    });
  });

  describe('doGenerate', () => {
    it('should send correct body with prompt and size', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: '1024x1024',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard-v1',
        prompt,
        n: 1,
        size: '1024x1024',
        response_format: 'b64_json',
      });
    });

    it('should default size to 512x512 when not specified', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).toMatchObject({ size: '512x512' });
    });

    it('should include style from providerOptions', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: { pixelart: { style: 'retro' } },
        files: undefined,
        mask: undefined,
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).toMatchObject({ style: 'retro' });
    });

    it('should include pixelDensity as pixel_density from providerOptions', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: { pixelart: { pixelDensity: 8 } },
        files: undefined,
        mask: undefined,
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).toMatchObject({ pixel_density: 8 });
    });

    it('should include both style and pixelDensity when both provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: '256x256',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: { pixelart: { style: '8bit', pixelDensity: 4 } },
        files: undefined,
        mask: undefined,
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).toStrictEqual({
        model: 'pixelart-standard-v1',
        prompt,
        n: 1,
        size: '256x256',
        style: '8bit',
        pixel_density: 4,
        response_format: 'b64_json',
      });
    });

    it('should omit style and pixelDensity when not specified', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: { pixelart: {} },
        files: undefined,
        mask: undefined,
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body.style).toBeUndefined();
      expect(body.pixel_density).toBeUndefined();
    });

    it('should return base64 images from response', async () => {
      server.urls[GENERATE_URL].response = {
        type: 'json-value',
        body: {
          created: 1700000000,
          data: [{ b64_json: 'aW1hZ2UxCg==' }, { b64_json: 'aW1hZ2UyCg==' }],
        },
      };

      const model = createBasicModel();
      const result = await model.doGenerate({
        prompt,
        n: 2,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.images).toHaveLength(2);
      expect(result.images[0]).toBe('aW1hZ2UxCg==');
      expect(result.images[1]).toBe('aW1hZ2UyCg==');
    });

    it('should include providerMetadata with images array and created timestamp', async () => {
      server.urls[GENERATE_URL].response = {
        type: 'json-value',
        body: {
          created: 1700000042,
          data: [
            { b64_json: 'abc=', style: 'pixel', pixel_density: 4 },
            { b64_json: 'def=' },
          ],
        },
      };

      const model = createBasicModel();
      const result = await model.doGenerate({
        prompt,
        n: 2,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.providerMetadata).toStrictEqual({
        pixelart: {
          images: [
            { style: 'pixel', pixelDensity: 4 },
            { style: null, pixelDensity: null },
          ],
          created: 1700000042,
        },
      });
    });

    it('should include response metadata with timestamp and modelId', async () => {
      const testDate = new Date('2024-06-01T00:00:00Z');
      const model = createBasicModel({ currentDate: () => testDate });

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.response).toStrictEqual({
        timestamp: testDate,
        modelId: 'pixelart-standard-v1',
        headers: expect.any(Object),
      });
    });

    describe('unsupported feature warnings', () => {
      it('should warn when aspectRatio is provided', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          n: 1,
          size: undefined,
          aspectRatio: '16:9',
          seed: undefined,
          providerOptions: {},
          files: undefined,
          mask: undefined,
        });

        expect(result.warnings).toContainEqual(
          expect.objectContaining({
            type: 'unsupported',
            feature: 'aspectRatio',
          }),
        );
      });

      it('should warn when seed is provided', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: 42,
          providerOptions: {},
          files: undefined,
          mask: undefined,
        });

        expect(result.warnings).toContainEqual(
          expect.objectContaining({ type: 'unsupported', feature: 'seed' }),
        );
      });

      it('should warn when files are provided', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
